import Mathlib

/-- The composition of two languages L1 and L2 is {x | ∃ y, x#y ∈ L1 ∧ y ∈ L2} where # is a separator. -/
def language_composition (L1 L2 : Set String) : Set String :=
  {x | ∃ y, ∃ h : String, x = y ++ "#" ++ h ∧ y ++ "#" ++ h ∈ L1 ∧ h ∈ L2}

